SET week_plan = $json$[{"week": 1, "theme": "第一周：“幽灵”之舞--幻肢现象与大脑的“地图”", "goals": "深入了解“幻肢”（Phantom Limb）现象的临床表现、普遍性及其带来的痛苦。学习神经科学中关于“身体地图”（Body Map）的主流理论解释（如大脑皮层重塑），并能清晰地阐述为何这些经典理论仍无法完全解释幻肢的所有奇特属性。", "day_count": 2}, {"week": 2, "theme": "第二周：伦理的深渊--在探索之前，我们首先是“人”", "goals": "学习并深入探讨与人体组织和个人体验相关的科学研究伦理原则。阅读并分析关于“幻肢与被截断肢体”的民俗学/人类学资料，理解其背后深刻的文化和心理意义。最终，为我们未来的思想实验，起草一份严格的、以“尊重”和“无伤害”为最高原则的《研究伦-理框架》。", "day_count": 2}, {"week": 3, "theme": "第三周：思想的“手术刀”--构建终极思想实验", "goals": "借鉴“生物贝尔实验”的逻辑框架，设计一个专门用于检验“幻肢”与“分离肢体”之间是否存在非定域性连接的思想实验方案。该方案需要包含清晰的“测量设置”与“结果”定义，并严格遵循上周制定的伦理框架。", "day_count": 2}, {"week": 4, "theme": "第四周：从思想实验到现实路径--伦理与可行性的交汇", "goals": "对上周设计的思想实验方案进行严格的“可行性与伦理”双重审查，识别出其在现实中执行的主要障碍。通过头脑风暴，设计一个或多个更具现实可行性的“简化版”或“替代版”实验方案。进行一次关于“科学隐喻”的哲学反思。", "day_count": 2}]$json$::jsonb,
